27	  const { comment, item_header_id, user_id, parent_id } = commentObj
28	  const inserted_date = new Date()
29	  return await sql.comments.create({
30	    comment,
31	    inserted_date,
32	    item_header_id,
33	    user_id,
34	    parent_id
35	  })
