38	CommentService.updateComment = async (id, body) => {
39	  const inserted_date = new Date()
40	  const comment = body.comment
41	  const instance = await sql.comments.findByPk(id);
42	  if (instance) {
43	    return await instance.update({ comment, inserted_date });
