1	'use strict';
2	
3	// Syncs staff users' Microsoft 365 / Teams profile photos into DO Spaces and
4	// persists the public URL on users.graph_photo. Uploaded photos always win over
5	// Graph photos (see effectivePhoto). Vendors are external (not in the M365
6	// tenant) so they are never synced here.
7	const { S3 } = require('@aws-sdk/client-s3');
8	const sql = require('../models/db');
9	const doConfig = require('../config/digitalocean.config');
10	const graphConfig = require('../config/graph.config');
11	const { fetchUserPhoto } = require('../helpers/graph');
12	
13	const s3Client = new S3({
14	  forcePathStyle: false,
15	  endpoint: doConfig.ENDPOINT_URL,
16	  region: 'us-west-1',
17	  credentials: {
18	    accessKeyId: doConfig.ACCESS_KEY,
19	    secretAccessKey: doConfig.SECRET_KEY,
20	  },
21	});
22	
23	// Re-check a user's M365 photo at most this often. The synced_at stamp is written
24	// even when the user has no photo, so we don't hammer Graph for photoless users.
25	const SYNC_TTL_MS = 7 * 24 * 60 * 60 * 1000; // 7 days
26	
27	function isFresh(syncedAt) {
28	  if (!syncedAt) return false;
29	  return Date.now() - new Date(syncedAt).getTime() < SYNC_TTL_MS;
30	}
31	
32	/** Effective avatar URL for a user row: uploaded photo wins, then Graph, then none. */
33	function effectivePhoto(user) {
34	  if (!user) return null;
35	  return user.profile_photo || user.graph_photo || null;
36	}
37	
38	function extFor(contentType) {
39	  return contentType && contentType.includes('png') ? '.png' : '.jpg';
40	}
41	
42	/**
43	 * Best-effort: fetch one staff user's M365 photo, cache it in DO Spaces, and
44	 * persist users.graph_photo + graph_photo_synced_at. Throttled by SYNC_TTL_MS.
45	 * Never throws. Returns the (possibly unchanged) graph_photo URL or null.
46	 *
47	 * @param {{id:number, email:string, profile_photo?:string, graph_photo?:string, graph_photo_synced_at?:Date}} user
48	 */
49	async function syncStaffPhoto(user) {
50	  if (!user || !graphConfig.isConfigured) return user ? user.graph_photo || null : null;
51	  const { id, email, graph_photo, graph_photo_synced_at } = user;
52	  if (!id || !email) return graph_photo || null;
53	  if (isFresh(graph_photo_synced_at)) return graph_photo || null;
54	
55	  const syncedAt = new Date();
56	
57	  let photo = null;
58	  try {
59	    photo = await fetchUserPhoto(email);
60	  } catch {
61	    photo = null;
62	  }
63	
64	  if (!photo) {
65	    // Stamp the attempt so photoless users aren't re-fetched on every request.
66	    try {
67	      await sql.users.update({ graph_photo_synced_at: syncedAt }, { where: { id } });
68	    } catch { /* best-effort */ }
69	    return graph_photo || null;
70	  }
71	
72	  const key = `profile-photos/graph-user-${id}${extFor(photo.contentType)}`;
73	  try {
74	    await s3Client.putObject({
75	      Bucket: doConfig.BUCKET_NAME,
76	      Key: key,
77	      Body: photo.buffer,
78	      ContentType: photo.contentType,
79	      ACL: 'public-read',
80	    });
81	    // Cache-bust so a refreshed M365 photo replaces the browser-cached copy.
82	    const url = `${doConfig.PUBLIC_URL}/${key}?v=${syncedAt.getTime()}`;
83	    await sql.users.update(
84	      { graph_photo: url, graph_photo_synced_at: syncedAt },
85	      { where: { id } }
86	    );
87	    return url;
88	  } catch (err) {
89	    console.warn(`graph-photo: caching failed for user ${id}:`, err.message);
90	    return graph_photo || null;
91	  }
92	}
93	
94	/**
95	 * Background backfill for a list of user rows: sync up to `max` staff users that
96	 * have no uploaded photo and are stale. Bounded so it never floods Graph; over
97	 * repeated calls (e.g. each mention-autocomplete load) the whole org fills in.
98	 * Fire-and-forget from callers (returns a promise but is safe to ignore).
99	 */
100	async function backfillStale(users, max = 10) {
101	  if (!graphConfig.isConfigured || !Array.isArray(users)) return;
102	  const stale = users
103	    .filter((u) => u && u.email && !u.profile_photo && !isFresh(u.graph_photo_synced_at))
104	    .slice(0, max);
105	  await Promise.all(stale.map((u) => syncStaffPhoto(u).catch(() => {})));
106	}
107	
108	module.exports = { syncStaffPhoto, backfillStale, effectivePhoto, isFresh, SYNC_TTL_MS };
