18	/**
19	 * GET /api/user/me
20	 * Returns the authenticated user's profile: { firstName, name, email, photoUrl }
21	 */
22	const getProfile = async (req, res) => {
23	  const user = await getUserInfo(req.headers.authorization);
24	  if (!user) return res.status(403).json({ message: 'Invalid token' });
25	  try {
26	    const profile = await UserService.getProfile(user);
27	    if (!profile) return res.status(404).json({ message: 'User not found' });
28	    return res.json(profile);
29	  } catch (err) {
30	    return res.status(500).json({ message: 'Server error', error: err.message });
31	  }
32	};
33	
34	/**
35	 * POST /api/user/photo
36	 * Accepts multipart/form-data field "photo".
37	 * Uploads to DO Spaces at key profile-photos/user-{userId}, stores URL in DB.
38	 * Returns { photoUrl }.
39	 */
40	const uploadProfilePhoto = async (req, res) => {
41	  const user = await getUserInfo(req.headers.authorization);
42	  if (!user) return res.status(403).json({ message: 'Invalid token' });
43	  if (!req.file) return res.status(400).json({ message: 'No file provided' });
44	
45	  const ext = path.extname(req.file.originalname).toLowerCase() || '.jpg';
46	  // Vendor ids and users ids are independent sequences — prefix the key by role
47	  // so a vendor and a staff user with the same numeric id never collide in the bucket.
48	  const keyPrefix = user.role === 'vendor' ? 'vendor' : 'user';
49	  const key = `profile-photos/${keyPrefix}-${user.user_id}${ext}`;
50	
51	  try {
52	    await s3Client.putObject({
53	      Bucket: doConfig.BUCKET_NAME,
54	      Key: key,
55	      Body: req.file.buffer,
56	      ContentType: req.file.mimetype,
57	      ACL: 'public-read',
58	    });
59	    const photoUrl = `${doConfig.PUBLIC_URL}/${key}`;
60	    await UserService.updateProfilePhoto(user, photoUrl);
61	    return res.json({ photoUrl });
62	  } catch (err) {
63	    return res.status(500).json({ message: 'Upload failed', error: err.message });
64	  }
65	};
66	
67	module.exports = { getProfile, uploadProfilePhoto };
