82	  updateComment(form: any) {
83	    this.itemService.updateComment(form.commentId, form.text).subscribe(data => {
84	      if (form.files.length > 0) {
85	        this.addAttachments(form.commentId, form.files)
86	      } else {
87	        this.getComments()
88	      }
89	      this.getReplies(form.commentId)
90	      this.activeComment = null;
91	    })
92	  }
93	
94	  addAttachments(commentId: number, files: any[]) {
95	    const fileCount = files.length;
96	    this.loading = true
97	    let href = document.location.href.split('/');
98	    const itemId = +href[href.length - 1];
99	
100	    // Iterate through each file in the files array
101	    for (let i = 0; i < fileCount; i++) {
102	      const file: File = files[i];
103	      const contentType = file.type;
104	      const fileName = `comments-${new Date().getTime()}-${file.name.toLowerCase()}`;
105	
106	      // Obtain the pre-signed URL for the current file
107	      this.itemService.getPreSignedUrl({ fileName, contentType })
108	        .subscribe((res: { signedUrl: string }) => {
109	          const signedUrl = res.signedUrl;
110	          const headers = new Headers({ 'Content-Type': contentType, 'x-amz-acl': 'public-read' });
111	          const putConfig = { method: 'PUT', body: file, headers: headers };
112	
113	          // Upload the file to the cloud storage using the signed URL
114	          fetch(signedUrl, putConfig)
115	            .then(output => {
116	              const body = {
117	                flag: 'comment-create-edit',
118	                item_num_id_fk: itemId,
119	                attachment_type: contentType,
120	                attachment_display_name: contentType.split("/")[0],
121	                fileName,
122	                comment_id: commentId
123	              };
124	              // Save the file link to your database
125	              this.itemService.saveTechLink(body, itemId)
126	                .pipe(take(1))
127	                .subscribe((res) => {
128	                  this.getComments()
129	                  if (i === 0) {
130	                    this.loading = false
131	                    this.childComponent.resetFileInput();
132	                  }
133	                })
134	            }).catch(error => {
135	              this.loading = false;
136	            });
137	        });
138	    }
139	  }
