149	  getReplies(commentId: number): CommentInterface[] {
150	    return this.comments
151	      .filter(comment => comment.parent_id === commentId)
152	      .sort((a, b) => new Date(a.inserted_date).getTime() - new Date(b.inserted_date).getTime());
153	  }
