159	  getUserInfo() {
160	    const token = localStorage.getItem('token');
161	    if (token) {
162	      const tokenPayload = <any>decode(token);
163	      this.userInfo = {
164	        userid: tokenPayload.user_id,
165	        name: tokenPayload.name,
166	        email: tokenPayload.email
167	      }
168	    }
