171	  getFormattedDate(inserted_date) {
172	    // Convert inserted_date to MM/DD/YY HH:MM:SS format
173	    const dateObj = new Date(inserted_date);
174	    const month = (dateObj.getMonth() + 1).toString().padStart(2, '0'); // Month is 0-based
175	    const day = dateObj.getDate().toString().padStart(2, '0');
176	    const year = dateObj.getFullYear().toString().slice(-2); // Get the last two digits of the year
177	    const hours = dateObj.getHours().toString().padStart(2, '0');
178	    const minutes = dateObj.getMinutes().toString().padStart(2, '0');
179	    const seconds = dateObj.getSeconds().toString().padStart(2, '0');
180	
181	    const formattedDate = `${month}/${day}/${year} ${hours}:${minutes}:${seconds}`;
182	    return formattedDate
183	  }
184	}

