682	    function formatDate(input) {
683	      if (input == null) return ''
684	      if (input.includes("-")) {
685	        var datePart = input.match(/\d+/g),
686	          year = datePart[0].substring(), // get only two digits
687	          month = datePart[1], day = datePart[2];
688	        return month + '/' + day + '/' + year;
689	      } else {
690	        return input
691	      }
692	    }
693	
694	    function monthToComparableNumber(date) {
695	
696	      if (date === undefined || date === null || date.length !== 10) {
697	        return date.length;
698	      }
699	      var yearNumber = date.substring(6, 10);
700	      var dayNumber = date.substring(3, 5);
701	      var monthNumber = date.substring(0, 2);
702	      var result = yearNumber * 10000 + monthNumber * 100 + dayNumber;
703	      return result;
704	    }
705	
706	
707	    date1 = formatDate(date1)
708	
709	    date2 = formatDate(date2)
710	
711	    var date1Number = monthToComparableNumber(date1);
712	    var date2Number = monthToComparableNumber(date2);
713	    if (date1Number === null && date2Number === null) {
714	      return 0;
715	    }
716	    if (date1Number === null) {
717	      return -1;
718	    }
719	    if (date2Number === null) {
720	      return 1;
721	    }
